#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
    int key;
    int cnt;
    struct Node* next;
} Node;

#define MOD 100003

Node* table[MOD];

unsigned int hash_int(int x) {
    return ((unsigned int)x * 2654435761u) % MOD;
}

Node* find(int x) {
    unsigned int h = hash_int(x);
    for (Node* p = table[h]; p; p = p->next) if (p->key == x) return p;
    return NULL;
}

void insert(int x) {
    unsigned int h = hash_int(x);
    Node* p = (Node*)malloc(sizeof(Node));
    p->key = x; p->cnt = 1; p->next = table[h];
    table[h] = p;
}

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        // clear hash table
        for(int i=0;i<MOD;i++){
            Node* p = table[i];
            while(p){ Node* nxt = p->next; free(p); p = nxt; }
            table[i]=NULL;
        }
        int max_f=0, max2=0;
        for(int i=0;i<N;i++){
            int x; scanf("%d", &x);
            Node* nd = find(x);
            if(nd){ nd->cnt++; }
            else { insert(x); nd = table[hash_int(x)]; }
            int c = nd->cnt;
            if(c > max_f){ max2 = max_f; max_f = c; }
            else if(c > max2 && c != max_f){ max2 = c; }
        }
        int ans = max2;
        int half = (max_f + 1) / 2;
        if(half > ans) ans = half;
        printf("%d\n", ans);
    }
    return 0;
}

